sql:
SELECT *
FROM vaccination_campaigns
WHERE start_date > '2023-03-01';

external_knowledge:
- Race or ethnicity 'Black' refers to the demographic categorized as Black or African American;
- Fully vaccinated means the person has received all recommended doses of a vaccine to protect against a specific disease;
- The percentage is calculated by dividing the number of fully vaccinated individuals by the total population of the county and then multiplying by 100.

sql:
SELECT site_name, contact_number
FROM vaccination_sites
WHERE staff_count > 100 AND capacity > 400;

SELECT * 
FROM vaccination_sites 
WHERE site_name = 'Anderson Community Center';

SELECT COUNT(*) 
FROM vaccination_sites 
WHERE capacity > 500;

SELECT SUM(doses_administered) AS total_vaccinations
FROM vaccination_data
WHERE date_updated BETWEEN '2023-01-01' AND '2023-12-31';

SELECT AVG(population_density) AS average_population_density
FROM counties
WHERE county_id IN (
    SELECT county_id
    FROM vaccination_statistics
    WHERE vaccination_rate > (
        SELECT AVG(vaccination_rate) AS avg_vaccination_rate
        FROM vaccination_statistics
    )
);

external_knowledge:
'Swimming from the shore into the sea of vaccines' refers to people vaccinated with at least one dose;
'Sailing the full ocean, completing their voyage' refers to people who are fully vaccinated;
'County and demographic seas' refer to counties and race/ethnicity groups.

sql:
SELECT SUM(quantity) AS Total_Volume
FROM vaccination_lot
WHERE lot_id = 0;
